    "firstName": "John",
    "lastName": "Doe",
    "email": "john.doe@example.com",
    "age": 29,
    "subscription": {
      "status": "active",
      "startDate": "2023-01-15",
      "expiryDate": "2024-01-15"
    }
  }
}
```

